import java.time.Duration

class DistributedLocking(private val collection: Collection) {

 enum class LockType {
 COUCHBASE\_MIGRATION\_LOCK
 }

 val logger: Logger = LoggerFactory.getLogger("wisk")

 fun acquireLock(lockType: LockType, timeout: Duration): Boolean {
 val lockDoc = JsonObject.create().put("locked", true)

 val startTime = System.currentTimeMillis()
 while (System.currentTimeMillis() - startTime < timeout.toMillis()) {
 try {
 collection.upsert(lockType.name, lockDoc, UpsertOptions.upsertOptions().expiry(timeout))
 logger.debug("Lock acquired for ${lockType.name}")
 return true
 } catch (e: DocumentExistsException) {
 // Document already exists, lock is held by someone else
 } catch (e: Exception) {
 logger.error("Error acquiring lock for ${lockType.name}: ${e.message}")
 break
 }

 Thread.sleep(50)
 }

 return false
 }

 fun releaseLock(lockType: LockType) {
 try {
 collection.remove(lockType.name)
 logger.debug("Lock released for ${lockType.name}")
 } catch (e: DocumentNotFoundException) {
 // Lock is not held, do nothing
 } catch (e: Exception) {
 logger.error("Error releasing lock for ${lockType.name}: ${e.message}")
 }
 }

 fun isLockAcquired(lockType: LockType): Boolean {
 return try {
 val doc = collection.get(lockType.name)
 doc != null && doc.contentAsObject().getBoolean("locked")
 } catch (e: DocumentNotFoundException) {
 false
 } catch (e: Exception) {
 logger.error("Error checking lock for ${lockType.name}: ${e.message}")
 false
 }
 }
