 function shuffleAndDealCards() {
 const ranks = ["ace", "2", "3", "4", "5", "6", "7", "8", "9", "10", "jack", "queen", "king"];
 const suits = ["hearts", "diamonds", "spades", "clubs"];

 const deck = [];
 suits.forEach(suit => {
 ranks.forEach(rank => {
 deck.push({rank: rank, suit: suit, image: `/images/${rank}\_of\_${suit}.png`, value: ranks.indexOf(rank) + 1}); 
 });
 });

 // Shuffle the deck
 for (let i = deck.length - 1; i > 0; i--) {
 const j = Math.floor(Math.random() \* (i + 1));
 [deck[i], deck[j]] = [deck[j], deck[i]];
 }

 // Split the deck into two arrays
 const player1 = deck.slice(0, 26);
 const player2 = deck.slice(26, 52);

 return [player1, player2];
 }

 let player1, player2;
let playerScore = 0;
let computerScore = 0;
const playerWins = [];
const computerWins = [];


 function checkIfAllCardsDealt() {
 return !player1 || !player2 || player1.length === 0 || player2.length === 0;
 }

function deal() {

 if (!player1 || !player2) {
 [player1, player2] = shuffleAndDealCards();
 }

 const card1 = player1.splice(Math.floor(Math.random() \* player1.length), 1)[0];
 const card2 = player2.splice(Math.floor(Math.random() \* player2.length), 1)[0];

 document.getElementById("card1").src = card1.image;
 document.getElementById("card2").src = card2.image;

 if (card1.value > card2.value) {
 playerScore++;
 playerWins.push(card1, card2);
 } else if (card1.value < card2.value) {
 computerScore++;
 computerWins.push(card1, card2);
 } else {
 playerWins.push(card1);
 computerWins.push(card2);
 }

 document.getElementById("player-score").textContent = `Player Score: ${playerScore}`;
 document.getElementById("computer-score").textContent = `Computer Score: ${computerScore}`;
}


function sendScore() {
 const playerName = prompt("Enter your name:");

 if (player1.length !== 0 || player2.length !== 0) {
 alert("Please deal all cards before sending score.");
 return;
 }

 const score = { name: playerName, playerScore: playerScore, computerScore: computerScore };

 fetch('save\_score.php', {
 method: 'POST',
 headers: {
 'Content-Type': 'application/json'
 },
 body: JSON.stringify(score)
 })
 .then(() => {
 alert("Score sent successfully!");
 })
 .catch(error => console.error(error));
}




